mapper.select:
select l.id as linkId, l.visit_kind as visitKind, l.mirror_row_id as mirrorRowId, l.alloc_qty as allocQty, l.in_hospital_code as inHospitalCode, ifnull(l.confirm_status, 0) as confirmStatus, l.confirm_id as confirmId, c.confirm_no as confirmNo, coalesce(h.audit_date, h.create_time, h.consume_bill_date) as consumeAuditTime, h.consume_bill_no as consumeBillNo, e.id as consumeEntryId, e.material_id as materialId, e.material_name as materialName, e.unit_price as unitPrice, coalesce(l.alloc_qty, e.qty) as entryQty, e.amt as amt, e.supplier_id as supplierId, sup.name as supplierName, e.batch_no as batchNo, h.department_id as departmentId, d.name as departmentName, coalesce(inp.patient_name, outp.patient_name) as patientName, coalesce(inp.inpatient_no, outp.outpatient_no) as visitNo, coalesce(inp.charge_item_id, outp.charge_item_id) as chargeItemId, coalesce(inp.item_name, outp.item_name) as itemName
and h.department_id = #{departmentId}
and ifnull(l.confirm_status, 0) = #{confirmStatus}
and coalesce(h.audit_date, h.create_time, h.consume_bill_date) >= #{beginConsumeAuditTime}
and coalesce(h.audit_date, h.create_time, h.consume_bill_date) <= #{endConsumeAuditTime}
and coalesce(inp.patient_name, outp.patient_name) like concat('%', #{patientName}, '%')
and coalesce(inp.inpatient_no, outp.outpatient_no) like concat('%', #{visitNo}, '%')
and coalesce(inp.charge_item_id, outp.charge_item_id) like concat('%', #{chargeItemId}, '%')
and e.material_name like concat('%', #{materialName}, '%')
order by consumeAuditTime desc, l.id desc

mapper.insert:
insert into gz_high_consume_confirm (
    id, tenant_id, confirm_no, department_id, warehouse_id,
    confirm_time, confirm_by, period_begin, period_end, remark,
    del_flag, create_by, create_time
) values (
    #{id}, #{tenantId}, #{confirmNo}, #{departmentId}, #{warehouseId},
    #{confirmTime}, #{confirmBy}, #{periodBegin}, #{periodEnd}, #{remark},
    ifnull(#{delFlag}, 0), #{createBy}, #{createTime}
)
